Here are the public test cases for feature10_partial_inclusion:
{
  "description": "Render named partial templates with explicit objects, repeated collections, local variables, nested partials, and dynamically selected partial names.",
  "cases": [
    {
      "input": {
        "template": "{% include 'product' with products[0] %}",
        "data": {
          "products": [
            {
              "title": "Draft 151cm"
            },
            {
              "title": "Element 155cm"
            }
          ]
        },
        "partials": {
          "product": "Product: {{ product.title }} "
        }
      },
      "expected_output": "Product: Draft 151cm "
    },
    {
      "input": {
        "template": "{% include 'product' for products %}",
        "data": {
          "products": [
            {
              "title": "Draft 151cm"
            },
            {
              "title": "Element 155cm"
            }
          ]
        },
        "partials": {
          "product": "Product: {{ product.title }} "
        }
      },
      "expected_output": "Product: Draft 151cm Product: Element 155cm "
    },
    {
      "input": {
        "template": "{% include 'locale_variables' echo1: 'test123', echo2: 'test321' %}",
        "partials": {
          "locale_variables": "Locale: {{echo1}} {{echo2}}"
        }
      },
      "expected_output": "Locale: test123 test321"
    }
  ]
}

Here are the public test cases for feature11_html_table_rows:
{
  "description": "Render table-row loops as HTML table row and cell fragments with row/column classes, counters, offset, and limit.",
  "cases": [
    {
      "input": {
        "template": "{% tablerow n in numbers cols:3%} {{n}} {% endtablerow %}",
        "data": {
          "numbers": [
            1,
            2,
            3,
            4,
            5,
            6
          ]
        }
      },
      "expected_output": "<tr class=\"row1\">\n<td class=\"col1\"> 1 </td><td class=\"col2\"> 2 </td><td class=\"col3\"> 3 </td></tr>\n<tr class=\"row2\"><td class=\"col1\"> 4 </td><td class=\"col2\"> 5 </td><td class=\"col3\"> 6 </td></tr>\n"
    },
    {
      "input": {
        "template": "{% tablerow n in numbers cols:2%}{{tablerowloop.col}}{% endtablerow %}",
        "data": {
          "numbers": [
            1,
            2,
            3,
            4,
            5,
            6
          ]
        }
      },
      "expected_output": "<tr class=\"row1\">\n<td class=\"col1\">1</td><td class=\"col2\">2</td></tr>\n<tr class=\"row2\"><td class=\"col1\">1</td><td class=\"col2\">2</td></tr>\n<tr class=\"row3\"><td class=\"col1\">1</td><td class=\"col2\">2</td></tr>\n"
    }
  ]
}

