Here are the public test cases for feature3_variable_resolution:
{
  "description": "Resolve scalar values, nested object paths, and missing values in output expressions.",
  "cases": [
    {
      "input": {
        "template": " {{best_cars}} ",
        "data": {
          "best_cars": "bmw",
          "car": {
            "bmw": "good",
            "gm": "bad"
          }
        }
      },
      "expected_output": " bmw "
    },
    {
      "input": {
        "template": " {{car.bmw}} {{car.gm}} {{car.bmw}} ",
        "data": {
          "best_cars": "bmw",
